def compute(inputs):
    tax_liability = inputs.get('tax_liability')
    tax_credit = inputs.get('tax_credit')
    refundable = inputs.get('refundable', False)
    if not isinstance(tax_liability, (int, float)) or not isinstance(tax_credit, (int, float)):
        raise ValueError('Tax liability and tax credit must be numeric values.')
    if not isinstance(refundable, bool):
        raise ValueError('Refundable flag must be a boolean value.')
    if tax_liability < 0 or tax_credit < 0:
        raise ValueError('Tax liability and tax credit must be non-negative values.')
    if refundable:
        remaining_liability = tax_liability - tax_credit
    else:
        remaining_liability = max(0, tax_liability - tax_credit)
    return remaining_liability

def compute(inputs):
    stock_price = inputs['stock_price']
    strike_price = inputs['strike_price']
    option_cost = inputs['option_cost']
    shares_per_contract = inputs['shares_per_contract']
    if stock_price >= strike_price:
        return -option_cost
    exercise_profit = (strike_price - stock_price) * shares_per_contract
    profit = exercise_profit - option_cost
    return round(profit)

def compute(inputs):
    principal = inputs['principal']
    annual_interest_rate = inputs['annual_interest_rate']
    period = inputs['period']
    monthly_interest_rate = annual_interest_rate / 12
    if monthly_interest_rate <= 0:
        raise ValueError('Annual interest rate must be positive.')
    monthly_payout = principal * monthly_interest_rate / (1 - (1 + monthly_interest_rate) ** (-period))
    return round(monthly_payout, 2)

def compute(inputs):
    current_gdp = inputs['current_gdp']
    previous_gdp = inputs['previous_gdp']
    gdp_growth_rate = (current_gdp - previous_gdp) / previous_gdp * 100
    return round(gdp_growth_rate, 2)

def compute(inputs):
    asset_price = inputs['asset_price']
    option_strike_price = inputs['option_strike_price']
    net_premium_paid = inputs['net_premium_paid']
    direction = inputs['direction']
    if direction == 'up':
        profit = asset_price - option_strike_price - net_premium_paid
    else:
        profit = option_strike_price - asset_price - net_premium_paid
    return profit

def compute(inputs):
    strike_price = inputs['strike_price']
    market_price = inputs['market_price']
    option_type = inputs['option_type']
    if option_type == 'call':
        intrinsic_value = max(0, market_price - strike_price)
    else:
        intrinsic_value = max(0, strike_price - market_price)
    return round(intrinsic_value)

def compute(inputs):
    itemized_deductions = inputs['itemized_deductions']
    standard_deduction = inputs['standard_deduction']
    tax_bracket = inputs['tax_bracket']
    if itemized_deductions > standard_deduction:
        tax_benefit = (itemized_deductions - standard_deduction) * tax_bracket
    else:
        tax_benefit = 0.0
    return round(tax_benefit, 2)

