def compute(inputs):
    loan_amount = inputs['loan_amount']
    annual_interest_rate = inputs['annual_interest_rate']
    loan_term_years = inputs['loan_term_years']
    monthly_interest_rate = annual_interest_rate / 12
    number_of_payments = loan_term_years * 12
    if monthly_interest_rate == 0:
        if number_of_payments == 0:
            return float('nan')
        return loan_amount / number_of_payments
    monthly_payment = loan_amount * (monthly_interest_rate * (1 + monthly_interest_rate) ** number_of_payments) / ((1 + monthly_interest_rate) ** number_of_payments - 1)
    return monthly_payment

def compute(inputs):
    prices = inputs['prices']
    weights = inputs['weights']
    if len(prices) != len(weights):
        raise ValueError('The length of prices and weights must be the same.')
    if not 0.999 <= sum(weights) <= 1.001:
        raise ValueError('Weights must sum to 1.')
    weighted_index = sum((price * weight for price, weight in zip(prices, weights)))
    return weighted_index

def compute(inputs):
    balance = inputs['balance']
    interest_rate = inputs['interest_rate']
    life_expectancy = inputs['life_expectancy']
    annual_payment = balance * interest_rate / (1 - (1 + interest_rate) ** (-life_expectancy))
    return round(annual_payment)

def compute(inputs):

    def calculate_pip_value_internal(trade_value: float, pip_size: float, exchange_rate: float=None) -> float:
        if exchange_rate is not None:
            pip_value = trade_value * (pip_size / exchange_rate)
        else:
